}

func newGateClock(now time.Time) gateClock {
	return gateClock{
		nowFunc: func() time.Time { return now },
	}
}

func (c gateClock) Now() time.Time {
	if c.nowFunc == nil {
		return time.Time{}
	}
	return c.nowFunc()
}

